import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import BookCard from '../components/BookCard';
import './Home.css';

export default function Home() {
  const [books, setBooks]     = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState('');

  useEffect(() => {
    fetch('/api/popular')
      .then(r => r.json())
      .then(data => { setBooks(data); setLoading(false); })
      .catch(() => { setError('Could not load books. Is Flask running?'); setLoading(false); });
  }, []);

  return (
    <div className="home">

      {/* ── HERO ── */}
      <section className="hero">
        <div className="hero__left">
          <span className="hero__badge">✦ AI-Powered Recommendations</span>
          <h1 className="hero__title">
            Discover Books<br />
            <span className="hero__title-em">You'll Love</span>
          </h1>
          <p className="hero__desc">
            Our collaborative filtering engine analyses millions of reader
            preferences to surface the perfect next book — just for you.
          </p>
          <div className="hero__btns">
            <Link to="/recommend" className="hero__btn-primary">
              Get My Recommendations
            </Link>
            <a href="#top50" className="hero__btn-secondary">
              Browse Top 50 ↓
            </a>
          </div>

          {/* Stats row */}
          <div className="hero__stats">
            {[
              { n: '50+',  l: 'Curated Books'     },
              { n: '270K+',l: 'Ratings Analysed'  },
              { n: '98%',  l: 'Happy Readers'      },
            ].map(s => (
              <div key={s.l} className="hero__stat">
                <strong>{s.n}</strong>
                <span>{s.l}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="hero__right">
          {/* Decorative stacked book covers from the first few books */}
          <div className="hero__books-display">
            {books.slice(0, 3).map((b, i) => (
              <div key={i} className={`hero__book-float hero__book-float--${i}`}>
                <img src={b.image} alt={b.title} />
              </div>
            ))}
            {books.length === 0 && (
              <>
                <div className="hero__book-float hero__book-float--0 skeleton" style={{width:140,height:200,borderRadius:12}} />
                <div className="hero__book-float hero__book-float--1 skeleton" style={{width:120,height:175,borderRadius:12}} />
                <div className="hero__book-float hero__book-float--2 skeleton" style={{width:110,height:160,borderRadius:12}} />
              </>
            )}
          </div>
        </div>
      </section>

      {/* ── TOP 50 SECTION ── */}
      <section className="top50-section" id="top50">
        <div className="container">

          <div className="top50-header">
            <div>
              <h2 className="top50-title">Top 50 Books</h2>
              <p className="top50-sub">Ranked by community ratings &amp; popularity</p>
            </div>
            <Link to="/recommend" className="top50-cta">
              Find Similar Books →
            </Link>
          </div>

          {error && (
            <div className="top50-error">⚠️ {error}</div>
          )}

          {loading ? (
            <div className="books-grid">
              {Array(12).fill(0).map((_, i) => (
                <div key={i} className="book-skeleton">
                  <div className="skeleton" style={{ height: 280, borderRadius: 12, marginBottom: 12 }} />
                  <div className="skeleton" style={{ height: 14, borderRadius: 6, marginBottom: 8 }} />
                  <div className="skeleton" style={{ height: 12, width: '65%', borderRadius: 6 }} />
                </div>
              ))}
            </div>
          ) : (
            <div className="books-grid">
              {books.map((b, i) => (
                <BookCard
                  key={i}
                  title={b.title}
                  author={b.author}
                  image={b.image}
                  rating={b.rating}
                  votes={b.votes}
                  rank={i + 1}
                  delay={Math.min(i * 35, 700)}
                />
              ))}
            </div>
          )}

        </div>
      </section>

      {/* ── HOW IT WORKS ── */}
      <section className="how-section">
        <div className="container">
          <h2 className="how-title">How It Works</h2>
          <p className="how-sub">Three steps to your next favourite book</p>
          <div className="how-steps">
            {[
              { icon: '🔍', step: '01', title: 'Search a Book', desc: 'Enter any book title you already enjoy into our search bar.' },
              { icon: '🤖', step: '02', title: 'AI Analyses', desc: 'Our model finds readers with similar tastes and surfaces their favourites.' },
              { icon: '📚', step: '03', title: 'Discover Reads', desc: 'Get 4 personalised recommendations with match scores.' },
            ].map(s => (
              <div key={s.step} className="how-card">
                <div className="how-card__icon">{s.icon}</div>
                <div className="how-card__step">{s.step}</div>
                <h3>{s.title}</h3>
                <p>{s.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

    </div>
  );
}
